const helpers = this.helpers;
const { telefono_wa, mensaje, cerrar } = $input.first().json.body;
const WA_TOKEN = $input.first().json._wa_token;
const PHONE_ID = $input.first().json._phone_id;
const SUPABASE_URL = $input.first().json._supa_url;
const SUPABASE_KEY = $input.first().json._supa_key;

await helpers.httpRequest({
  method: 'POST',
  url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
  headers: { Authorization: `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({ messaging_product: 'whatsapp', to: telefono_wa, type: 'text', text: { body: mensaje } })
});

if (cerrar) {
  await helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
    qs: { telefono_wa: `eq.${telefono_wa}` },
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ handoff_humano: false, estado: 'inicio', contexto: {}, updated_at: new Date().toISOString() })
  });
}

return [{ json: { success: true } }];
